import pytest
import requests

BASE_URL = "http://hr-app"

def test_delete_already_deleted_payroll_run_is_idempotent_or_404():
    token = <get_hr_admin_token>()
    run_id = <create_payroll_run_fixture>(token)
    headers = {"Authorization": f"Bearer {token}"}

    first = requests.delete(
        f"{BASE_URL}/api/payroll-runs/{run_id}", headers=headers
    )
    assert first.status_code in (200, 201), (
        f"First delete failed unexpectedly: {first.status_code}"
    )

    second = requests.delete(
        f"{BASE_URL}/api/payroll-runs/{run_id}", headers=headers
    )
    assert second.status_code in (404, 409), (
        f"Expected 404 or 409 on re-delete, got {second.status_code}"
    )

    audit_count = <count_audit_records>(run_id, token)
    assert audit_count == 1, (
        f"Expected exactly 1 audit record, found {audit_count}"
    )
